// ==================== Network Client (Singleton Builder) ====================

package com.example.networking

import com.example.networking.api.UserApiService
import com.google.gson.GsonBuilder
import okhttp3.OkHttpClient
import okhttp3.logging.HttpLoggingInterceptor
import retrofit2.Retrofit
import retrofit2.converter.gson.GsonConverterFactory
import java.util.concurrent.TimeUnit

object NetworkClient {

    private var environment: Environment = Environment.DEV
    private var tokenProvider: TokenProvider = InMemoryTokenProvider()
    private var retrofit: Retrofit? = null
    private var okHttpClient: OkHttpClient? = null

    fun initialize(
        environment: Environment,
        tokenProvider: TokenProvider = InMemoryTokenProvider()
    ) {
        this.environment = environment
        this.tokenProvider = tokenProvider
        // Reset so they are rebuilt with new config
        this.retrofit = null
        this.okHttpClient = null
    }

    fun setEnvironment(env: Environment) {
        this.environment = env
        this.retrofit = null
        this.okHttpClient = null
    }

    fun getTokenProvider(): TokenProvider = tokenProvider

    private fun buildOkHttpClient(): OkHttpClient {
        if (okHttpClient != null) return okHttpClient!!

        val loggingInterceptor = HttpLoggingInterceptor().apply {
            level = when (environment) {
                Environment.DEV -> HttpLoggingInterceptor.Level.BODY
                Environment.STAGING -> HttpLoggingInterceptor.Level.HEADERS
                Environment.PRODUCTION -> HttpLoggingInterceptor.Level.NONE
            }
        }

        okHttpClient = OkHttpClient.Builder()
            .addInterceptor(AuthInterceptor(tokenProvider))
            .addInterceptor(loggingInterceptor)
            .authenticator(TokenAuthenticator(tokenProvider))
            .connectTimeout(30, TimeUnit.SECONDS)
            .readTimeout(30, TimeUnit.SECONDS)
            .writeTimeout(30, TimeUnit.SECONDS)
            .build()

        return okHttpClient!!
    }

    private fun buildRetrofit(): Retrofit {
        if (retrofit != null) return retrofit!!

        val gson = GsonBuilder()
            .setLenient()
            .create()

        retrofit = Retrofit.Builder()
            .baseUrl(environment.baseUrl)
            .client(buildOkHttpClient())
            .addConverterFactory(GsonConverterFactory.create(gson))
            .build()

        return retrofit!!
    }

    val userApiService: UserApiService by lazy(LazyThreadSafetyMode.SYNCHRONIZED) {
        buildRetrofit().create(UserApiService::class.java)
    }

    // Generic service creator for extensibility
    fun <T> createService(serviceClass: Class<T>): T {
        return buildRetrofit().create(serviceClass)
    }
}

