package com.example.networking.repository

import com.example.networking.NetworkClient
import com.example.networking.NetworkResult
import com.example.networking.model.UserProfile
import com.example.networking.model.UsersResponse
import retrofit2.Response

class UserRepository {

    private val apiService = NetworkClient.userApiService

    suspend fun getUsers(page: Int = 1, perPage: Int = 20): NetworkResult<UsersResponse> {
        return safeApiCall { apiService.getUsers(page, perPage) }
    }

    suspend fun getUserById(userId: Long): NetworkResult<UserProfile> {
        return safeApiCall { apiService.getUserById(userId) }
    }

    suspend fun getCurrentUser(): NetworkResult<UserProfile> {
        return safeApiCall { apiService.getCurrentUser() }
    }

    suspend fun createUser(user: UserProfile): NetworkResult<UserProfile> {
        return safeApiCall { apiService.createUser(user) }
    }

    suspend fun updateUser(userId: Long, user: UserProfile): NetworkResult<UserProfile> {
        return safeApiCall { apiService.updateUser(userId, user) }
    }

    suspend fun deleteUser(userId: Long): NetworkResult<Unit> {
        return safeApiCall { apiService.deleteUser(userId) }
    }

    private suspend fun <T> safeApiCall(apiCall: suspend () -> Response<T>): NetworkResult<T> {
        return try {
            val response = apiCall()
            if (response.isSuccessful) {
                val body = response.body()
                if (body != null) {
                    NetworkResult.Success(body)
                } else {
                    NetworkResult.Error(response.code(), "Response body is null")
                }
            } else {
                val errorBody = response.errorBody()?.string() ?: "Unknown error"
                NetworkResult.Error(response.code(), errorBody)
            }
        } catch (e: Exception) {
            NetworkResult.Exception(e)
        }
    }
}

